
var userState = { name:'', email:'', usage:0, alertLimit:150 };
var billFiles = [];
var feedbacks = [];

function safeStorageGet(key) {
  try {
    return localStorage.getItem(key);
  } catch (err) {
    return null;
  }
}

function safeStorageSet(key, value) {
  try {
    localStorage.setItem(key, value);
  } catch (err) {}
}

function safeStorageRemove(key) {
  try {
    localStorage.removeItem(key);
  } catch (err) {}
}

function deriveDisplayName(email) {
  var prefix = (email || '').split('@')[0] || '';
  prefix = prefix.replace(/[._-]+/g, ' ').trim();
  if (!prefix) return 'مستخدم وفرها';
  return prefix;
}

function performLogin() {
  var nameInput = document.getElementById('userNameInput');
  var emailInput = document.getElementById('userEmailInput');
  var rawName = nameInput ? nameInput.value.trim() : '';
  var email = emailInput ? emailInput.value.trim() : '';

  if (!email) {
    alert('الرجاء إدخال البريد الإلكتروني');
    if (emailInput) emailInput.focus();
    return;
  }

  if (emailInput && typeof emailInput.checkValidity === 'function' && !emailInput.checkValidity()) {
    alert('الرجاء إدخال بريد إلكتروني صحيح');
    emailInput.focus();
    return;
  }

  userState.name = rawName || deriveDisplayName(email);
  userState.email = email;

  saveSession();
  showDashboard();
}

window.performLogin = performLogin;

// ---- central refresh: updates gauge + stat cards + week bars + saving hint ----
function refreshAll() {
  updateGauge();
  updateStatCards();
  updateSavingHint();
  renderWeekBars();
}

function updateSavingHint() {
  var el = document.getElementById('savingHintCard');
  if (!el) return;
  var usage = userState.usage;
  var limit = userState.alertLimit;
  if (usage === 0) {
    el.innerHTML = '<div style="font-size:13px;font-weight:700;color:#64748B;text-align:center;padding:12px 0;">⏳ لم يتم تسجيل استهلاك بعد — أضف فاتورتك أو سجّل يدوياً</div>';
    return;
  }
  var target = Math.round(limit * 0.75); // target = 75% of limit
  var savePct = usage > target ? Math.round(((usage - target) / usage) * 100) : 0;
  var color = savePct >= 20 ? '#dc2626' : savePct >= 10 ? '#f59e0b' : '#16a34a';
  var emoji = savePct >= 20 ? '🔴' : savePct >= 10 ? '🟡' : '🟢';
  if (savePct > 0) {
    el.innerHTML = emoji + ' <b>حاولي توفري ' + savePct + '% من استهلاكك</b> — أنتِ تستهلكين <b>' + usage + ' لتر</b> والهدف المثالي <b>' + target + ' لتر</b> يومياً. توفيري <b>' + (usage - target) + ' لتر/يوم</b> يوفّر <b>' + Math.round((usage - target) * 30) + ' لتر/شهر</b>.';
    el.style.background = savePct >= 20 ? '#fff1f2' : savePct >= 10 ? '#fffbeb' : '#f0fdf4';
    el.style.borderColor = savePct >= 20 ? '#fecaca' : savePct >= 10 ? '#fde68a' : '#bbf7d0';
    el.style.color = color;
  } else {
    el.innerHTML = '🟢 <b>رائع! استهلاكك ممتاز</b> — أنتِ تستهلكين <b>' + usage + ' لتر</b>، وهو أقل من الهدف المثالي البالغ <b>' + target + ' لتر</b>. استمري! 💪';
    el.style.background = '#f0fdf4';
    el.style.borderColor = '#bbf7d0';
    el.style.color = '#16a34a';
  }
}

document.addEventListener('DOMContentLoaded', function() {
  window.addEventListener('resize', function() {
    if (window.innerWidth >= 768) closeMobileMenu();
  });

  var loginBtn = document.getElementById('loginBtn');
  if (loginBtn) {
    loginBtn.addEventListener('click', function(evt) {
      evt.preventDefault();
      performLogin();
    });
  }

  document.getElementById('demoBtn').addEventListener('click', function() {
    userState.name = 'المستخدم التجريبي'; userState.email = 'demo@waferha.sa';
    saveSession(); showDashboard();
  });

  document.getElementById('logValueBtn').addEventListener('click', function() {
    var val = parseInt(document.getElementById('logLitersInput').value);
    if (!val || val <= 0) { alert('الرجاء إدخال كمية صحيحة'); return; }

    // Which day was selected?
    var dayNames = ['السبت','الأحد','الإثنين','الثلاثاء','الأربعاء','الخميس','الجمعة'];
    var dayMap   = { 'السبت':6,'الأحد':0,'الإثنين':1,'الثلاثاء':2,'الأربعاء':3,'الخميس':4,'الجمعة':5 };
    var selectedDay = document.getElementById('logDaySelector').value;
    var selectedIdx = dayMap[selectedDay] !== undefined ? dayMap[selectedDay] : todayIdx;

    // Save this day's data persistently
    saveDayUsage(selectedIdx, val);

    // Only update the live gauge/stats if it's today's day
    if (selectedIdx === todayIdx) {
      userState.usage = val;
      refreshAll();
    } else {
      // Just re-render bars to show the new bar, keep gauge as-is
      renderWeekBars();
      // Flash the saved day label
      var cols = document.querySelectorAll('.day-bar-col');
      if (cols[selectedIdx]) {
        cols[selectedIdx].style.transition = 'opacity .1s';
        cols[selectedIdx].style.opacity = '0.4';
        setTimeout(function(){ cols[selectedIdx].style.opacity = '1'; }, 200);
      }
    }
    document.getElementById('logLitersInput').value = '';
  });

  document.getElementById('updateLimitBtn').addEventListener('click', function() {
    var lim = parseInt(document.getElementById('alertLimitSetterInput').value);
    if (!lim || lim < 50) { alert('الحد الأدنى 50 لتر'); return; }
    userState.alertLimit = lim; safeStorageSet('activeWaterLimit', lim);
    refreshAll();
  });

  document.getElementById('submitFeedbackBtn').addEventListener('click', function() {
    var msg = document.getElementById('feedbackMessage').value.trim();
    if (!msg) { alert('الرجاء كتابة الملاحظة'); return; }
    feedbacks.unshift({ id:'f'+Date.now(), senderName:userState.name||'مستخدم', email:userState.email||'guest@waferha.sa',
      type:document.getElementById('feedbackType').value, message:msg, date:new Date().toISOString().split('T')[0] });
    renderFeedbacks(); document.getElementById('feedbackMessage').value = '';
    alert('تم إرسال مقترحك بنجاح!');
  });

  var cached = safeStorageGet('activeWaterSession');
  if (cached) {
    userState.email = cached;
    userState.name = safeStorageGet('activeWaterName') || 'مستخدم وفرها';
    userState.usage = 0; // دايماً يبدأ صفر
    userState.alertLimit = parseInt(safeStorageGet('activeWaterLimit')) || 150;
    showDashboard();
  }
});

function saveSession() {
  safeStorageSet('activeWaterSession', userState.email);
  safeStorageSet('activeWaterName', userState.name);
  safeStorageSet('activeWaterLimit', userState.alertLimit);
  // usage لا يُحفظ — يبدأ من صفر كل جلسة جديدة
}

function syncUserBadges() {
  var initial = userState.name ? userState.name.charAt(0) : 'م';
  var mainBadge = document.getElementById('userInitial');
  var mobileBadge = document.getElementById('mobileUserInitial');
  if (mainBadge) mainBadge.textContent = initial;
  if (mobileBadge) mobileBadge.textContent = initial;
}

function openMobileMenu() {
  var sidebar = document.querySelector('.sidebar');
  var backdrop = document.getElementById('sidebarBackdrop');
  if (!sidebar || !backdrop) return;
  sidebar.classList.add('open');
  backdrop.classList.add('show');
  document.body.style.overflow = 'hidden';
}

function closeMobileMenu() {
  var sidebar = document.querySelector('.sidebar');
  var backdrop = document.getElementById('sidebarBackdrop');
  if (!sidebar || !backdrop) return;
  sidebar.classList.remove('open');
  backdrop.classList.remove('show');
  document.body.style.overflow = '';
}

function toggleMobileMenu() {
  var sidebar = document.querySelector('.sidebar');
  if (!sidebar) return;
  if (sidebar.classList.contains('open')) closeMobileMenu();
  else openMobileMenu();
}

function showDashboard() {
  var authScreen = document.getElementById('authScreen');
  var mainDashboard = document.getElementById('mainDashboard');

  if (authScreen) authScreen.style.display = 'none';
  if (mainDashboard) {
    mainDashboard.style.display = 'flex';
    mainDashboard.classList.add('show');
  }

  try {
    var profileName = document.getElementById('profileName');
    var profileEmail = document.getElementById('profileEmail');
    if (profileName) profileName.textContent = userState.name;
    if (profileEmail) profileEmail.textContent = userState.email;
    syncUserBadges();
    closeMobileMenu();
    refreshAll();
    calculateSavings();
    renderFeedbacks();
    setTimeout(function(){
      renderWeekBars();
      updateStatCards();
      updateSavingHint();
    }, 100);
  } catch (err) {
    console.error('showDashboard failed:', err);
  }
}

function handleLogout() {
  ['activeWaterSession','activeWaterName','activeWaterUsage','activeWaterLimit'].forEach(function(k){ safeStorageRemove(k); });
  closeMobileMenu();
  document.getElementById('mainDashboard').style.display = 'none';
  document.getElementById('mainDashboard').classList.remove('show');
  document.getElementById('authScreen').style.display = 'flex';
}

function updateGauge() {
  var usage = userState.usage;
  var limit = userState.alertLimit;
  var pct = usage === 0 ? 0 : Math.min(100, Math.round((usage / limit) * 100));
  document.getElementById('gaugeLitersVal').textContent = usage === 0 ? '—' : usage;
  document.getElementById('gaugeLimitText').textContent = limit;
  document.getElementById('currentLimitDisplay').textContent = 'الحد الأقصى: ' + limit + ' لتر';
  document.getElementById('alertLimitSetterInput').value = limit;
  document.getElementById('gaugePercentText').textContent = usage === 0 ? 'لم يُسجَّل استهلاك بعد' : pct + '% من المستهدف';
  var wave = document.getElementById('waterLevelWave');
  wave.style.height = pct + '%';
  if (pct >= 100) {
    wave.style.background = 'linear-gradient(180deg,rgba(248,113,113,.45) 0%,rgba(239,68,68,.65) 100%)';
    document.getElementById('bellIcon').style.stroke = '#ef4444';
    document.getElementById('alertPulse').style.display = 'block';
  } else {
    wave.style.background = 'linear-gradient(180deg,rgba(96,165,250,.45) 0%,rgba(59,130,246,.65) 100%)';
    document.getElementById('bellIcon').style.stroke = '#3B82F6';
    document.getElementById('alertPulse').style.display = 'none';
  }
}

function switchTab(id) {
  document.querySelectorAll('.view').forEach(function(v){ v.classList.remove('active'); });
  document.getElementById('view-'+id).classList.add('active');
  document.querySelectorAll('.tab-btn').forEach(function(b){ b.classList.remove('active'); });
  document.getElementById('btn-tab-'+id).classList.add('active');
  closeMobileMenu();
  if (id === 'analytics' && typeof window.renderAnalyticsView === 'function') {
    window.renderAnalyticsView();
  }
}

// ============ CHATBOT ============
var chatStep = 0;
var userAge = 0;

var botMessages = [
  { text: 'أهلاً وسهلاً! 👋 أنا مساعد وفرها الذكي. قبل ما تبدأ، عايز أتعرف عليك شوية 😊' },
  { text: 'كم عمرك؟ (اكتب رقم السن)' }
];

function chatAddBotMsg(text, delay) {
  delay = delay || 0;
  setTimeout(function() {
    // typing indicator
    var msgs = document.getElementById('chatMsgs');
    var typing = document.createElement('div');
    typing.className = 'msg-bot';
    typing.id = 'typingIndicator';
    typing.innerHTML = '<div class="msg-bot-avatar">💧</div><div class="msg-bubble-bot"><div class="typing"><span></span><span></span><span></span></div></div>';
    msgs.appendChild(typing);
    msgs.scrollTop = msgs.scrollHeight;
    setTimeout(function() {
      var t = document.getElementById('typingIndicator');
      if (t) t.remove();
      var el = document.createElement('div');
      el.className = 'msg-bot';
      el.innerHTML = '<div class="msg-bot-avatar">💧</div><div class="msg-bubble-bot">' + text + '</div>';
      msgs.appendChild(el);
      msgs.scrollTop = msgs.scrollHeight;
    }, 800);
  }, delay);
}

function chatAddUserMsg(text) {
  var msgs = document.getElementById('chatMsgs');
  var el = document.createElement('div');
  el.innerHTML = '<div class="msg-bubble-user">' + text + '</div>';
  msgs.appendChild(el);
  msgs.scrollTop = msgs.scrollHeight;
}

function chatSetOptions(opts) {
  var c = document.getElementById('chatOptions');
  c.innerHTML = '';
  opts.forEach(function(o) {
    var b = document.createElement('button');
    b.className = 'chat-opt-btn';
    b.textContent = o.label;
    b.onclick = function() { o.action(); };
    c.appendChild(b);
  });
}

function submitAge() {
  var val = parseInt(document.getElementById('chatTextInput').value);
  if (!val || val < 5 || val > 110) { alert('أدخل عمر صحيح'); return; }
  userAge = val;
  chatAddUserMsg(val + ' سنة');
  document.getElementById('chatInputRow').style.display = 'none';
  document.getElementById('chatTextInput').value = '';
  chatStep = 2;
  chatAddBotMsg('تمام! عمرك ' + val + ' سنة 🙏', 200);
  chatAddBotMsg('سؤال مهم: هل تعرف أهمية ترشيد استهلاك المياه؟ 💧', 1200);
  setTimeout(function() {
    chatSetOptions([
      { label: 'نعم، أعرف 👍', action: function() { handleAwarenessAnswer(true); } },
      { label: 'لا، مش عارف 🤔', action: function() { handleAwarenessAnswer(false); } }
    ]);
  }, 2200);
}

function handleAwarenessAnswer(knows) {
  chatSetOptions([]);
  if (knows) {
    chatAddUserMsg('نعم، أعرف 👍');
    chatAddBotMsg('برافو عليك! 🎉 معرفتك بأهمية ترشيد المياه خطوة رائعة. وفرها هنا لمساعدتك تتابع استهلاكك وتوفر أكثر! 💪', 200);
  } else {
    chatAddUserMsg('لا، مش عارف 🤔');
    chatAddBotMsg('لا بأس! هقولك بالاختصار 💡<br><br>🌍 <b>المياه مورد محدود</b> — 97% من مياه الأرض مالحة وغير صالحة للشرب.<br>💸 <b>توفر فلوسك</b> — تقليل الاستهلاك يخفض فاتورتك بشكل كبير.<br>🌱 <b>للأجيال القادمة</b> — ترشيد اليوم يضمن مياه نظيفة لأطفالنا.<br><br>كل لتر بتوفره يفرق! 🚿', 200);
  }
  setTimeout(function() {
    chatAddBotMsg('الآن يمكنك الاستمتاع بكل ميزات وفرها. يلا نبدأ! 🚀', 2000);
    setTimeout(function() {
      chatSetOptions([
        { label: 'دخول للوحة التحكم ✅', action: closeChatbot }
      ]);
    }, 3000);
  }, knows ? 1500 : 3500);
}

var chatOpened = false;

function toggleChat() {
  var popup = document.getElementById('chatbotPopup');
  var isOpen = popup.classList.contains('open');
  if (isOpen) {
    popup.style.opacity = '0';
    popup.style.transform = 'scale(.95) translateY(10px)';
    setTimeout(function() { popup.classList.remove('open'); }, 250);
  } else {
    popup.classList.add('open');
    setTimeout(function() {
      popup.style.opacity = '1';
      popup.style.transform = 'scale(1) translateY(0)';
    }, 10);
    // hide red dot once opened
    document.getElementById('chatFabDot').style.display = 'none';
    // start chat messages only first time
    if (!chatOpened) {
      chatOpened = true;
      chatAddBotMsg(botMessages[0].text, 300);
      chatAddBotMsg(botMessages[1].text, 1200);
      setTimeout(function() {
        document.getElementById('chatInputRow').style.display = 'flex';
        document.getElementById('chatTextInput').focus();
      }, 2200);
      setTimeout(function() {
        chatSetOptions([
          { label: 'التحليلات', action: function() { closeChatbot(); switchTab('analytics'); } },
          { label: 'رفع JSON', action: function() { triggerAnalyticsJsonUpload(); } },
          { label: 'مشاركة PDF', action: function() { shareAnalyticsReport(); } }
        ]);
      }, 2400);
    }
  }
}

function closeChatbot() {
  var popup = document.getElementById('chatbotPopup');
  popup.style.opacity = '0';
  popup.style.transform = 'scale(.95) translateY(10px)';
  setTimeout(function() { popup.classList.remove('open'); popup.style.display = 'none'; }, 250);
}
// ============ AD GENERATOR ============
var lastAdText = '';

document.addEventListener('DOMContentLoaded', function() {
  var genBtn = document.getElementById('generateAdBtn');
  if (genBtn) {
    genBtn.addEventListener('click', generateAd);
  }
});

function generateAd() {
  var audience = document.getElementById('adAudience').value;
  var tone     = document.getElementById('adTone').value;
  var message  = document.getElementById('adMessage').value.trim();
  var platform = document.getElementById('adPlatform').value;

  if (!message) {
    document.getElementById('adMessage').focus();
    document.getElementById('adMessage').style.borderColor = '#ef4444';
    setTimeout(function(){ document.getElementById('adMessage').style.borderColor = ''; }, 1500);
    return;
  }

  var btn = document.getElementById('generateAdBtn');
  btn.disabled = true;
  btn.innerHTML = '<div style="width:16px;height:16px;border:2px solid #fff;border-top-color:transparent;border-radius:50%;animation:spin .8s linear infinite;display:inline-block;vertical-align:middle;margin-left:6px;"></div> جاري التوليد...';

  document.getElementById('adOutputBody').innerHTML =
    '<div style="text-align:center;padding:32px 0;">' +
    '<div style="width:40px;height:40px;border:3px solid #3B82F6;border-top-color:transparent;border-radius:50%;animation:spin .8s linear infinite;margin:0 auto 16px;"></div>' +
    '<div style="font-size:13px;font-weight:700;color:#64748B;">جاري توليد الإعلان...</div></div>';
  document.getElementById('copyAdBtn').style.display = 'none';

  setTimeout(function() {
    var ad = buildAdOffline(audience, tone, message, platform);
    lastAdText = ad.plain;

    var html = '<div style="background:#f8fafc;border-radius:16px;padding:20px;font-size:13px;line-height:2;color:#1E293B;direction:rtl;text-align:right;">';
    html += '<div style="font-weight:900;color:#1E3A8A;margin-bottom:6px;">🎯 العنوان:</div>';
    html += '<div style="font-size:15px;font-weight:800;color:#1E293B;margin-bottom:14px;">' + ad.title + '</div>';
    html += '<div style="font-weight:900;color:#1E3A8A;margin-bottom:6px;">📝 نص الإعلان:</div>';
    html += '<div style="margin-bottom:14px;">' + ad.body + '</div>';
    html += '<div style="font-weight:900;color:#1E3A8A;margin-bottom:6px;">💡 نداء للتصرف:</div>';
    html += '<div style="margin-bottom:14px;">' + ad.cta + '</div>';
    html += '<div style="color:#3B82F6;font-weight:700;">' + ad.tags + '</div>';
    html += '</div>';

    document.getElementById('adOutputBody').innerHTML = html;
    document.getElementById('copyAdBtn').style.display = 'block';

    btn.disabled = false;
    btn.innerHTML = '<svg viewBox="0 0 24 24" style="width:16px;height:16px;stroke:#fff;fill:none;stroke-width:2;"><path d="M12 3l1.912 5.813a2 2 0 0 0 1.275 1.275L21 12l-5.813 1.912a2 2 0 0 0-1.275 1.275L12 21l-1.912-5.813a2 2 0 0 0-1.275-1.275L3 12l5.813-1.912a2 2 0 0 0 1.275-1.275L12 3z"/></svg> ولّد الإعلان الآن';
  }, 1200);
}

function buildAdOffline(audience, tone, message, platform) {
  var toneMap = {
    '\u062a\u0648\u0639\u0648\u064a \u0648\u0639\u0627\u0637\u0641\u064a': { open: '\ud83d\udc99 ', emo: '\u0643\u0644 \u0642\u0637\u0631\u0629 \u0628\u062a\u0641\u0631\u0642...', close: '\u0644\u0623\u0646 \u0627\u0644\u0645\u064a\u0627\u0647 \u062d\u064a\u0627\u0629\u060c \u0645\u0634 \u0628\u0633 \u0635\u0646\u0628\u0648\u0631.' },
    '\u0639\u0645\u0644\u064a \u0648\u0645\u0628\u0627\u0634\u0631': { open: '\u2705 ', emo: '\u0627\u0644\u062d\u0642\u064a\u0642\u0629 \u0628\u0627\u0644\u0623\u0631\u0642\u0627\u0645:', close: '\u0627\u0628\u062f\u0623 \u0627\u0644\u062a\u0648\u0641\u064a\u0631 \u0645\u0646 \u0627\u0644\u0646\u0647\u0627\u0631\u062f\u0647.' },
    '\u062a\u062d\u0641\u064a\u0632\u064a \u0648\u062d\u0645\u0627\u0633\u064a': { open: '\ud83d\udd25 ', emo: '\u0625\u0646\u062a \u0642\u0627\u062f\u0631 \u062a\u0639\u0645\u0644 \u0641\u0631\u0642 \u062d\u0642\u064a\u0642\u064a!', close: '\u062e\u0644\u064a\u0643 \u062c\u0632\u0621 \u0645\u0646 \u0627\u0644\u062d\u0644 \u2014 \u0645\u0634 \u0627\u0644\u0645\u0634\u0643\u0644\u0629! \ud83d\udcaa' },
    '\u062e\u0641\u064a\u0641 \u0648\u0645\u0631\u062d': { open: '\ud83d\ude04 ', emo: '\u0628\u0635\u0631\u0627\u062d\u0629...', close: '\u0648\u0627\u0644\u0644\u0647 \u0627\u0644\u0645\u064a\u0627\u0647 \u0645\u0634 \u0647\u062a\u0639\u062f\u064a \u062a\u0627\u0646\u064a! \ud83d\ude05\ud83d\udca7' },
    '\u0631\u0633\u0645\u064a \u0648\u0627\u062d\u062a\u0631\u0627\u0641\u064a': { open: '\ud83c\udfaf ', emo: '\u0648\u0641\u0642\u0627\u064b \u0644\u0623\u062d\u062f\u062b \u0627\u0644\u062f\u0631\u0627\u0633\u0627\u062a:', close: '\u062a\u0631\u0634\u064a\u062f \u0627\u0644\u0645\u064a\u0627\u0647: \u0645\u0633\u0624\u0648\u0644\u064a\u0629 \u062c\u0645\u0627\u0639\u064a\u0629 \u0648\u0636\u0631\u0648\u0631\u0629 \u0648\u0637\u0646\u064a\u0629.' }
  };
  var t = toneMap[tone] || toneMap['\u062a\u0648\u0639\u0648\u064a \u0648\u0639\u0627\u0637\u0641\u064a'];
  var audHook = {
    '\u0631\u0628\u0627\u062a \u0627\u0644\u0628\u064a\u0648\u062a \u0641\u064a \u0645\u0635\u0631': '\u064a\u0627 \u0633\u062a \u0627\u0644\u0628\u064a\u062a\u060c \u0625\u0646\u062a\u064a \u0642\u0644\u0628 \u0627\u0644\u0628\u064a\u062a \u0648\u0625\u064a\u062f\u0643 \u0628\u062a\u062d\u0643\u0645 \u0641\u064a \u0627\u0644\u0645\u064a\u0627\u0647 \u0643\u0644 \u064a\u0648\u0645.',
    '\u0627\u0644\u0634\u0628\u0627\u0628 \u0648\u0627\u0644\u0637\u0644\u0627\u0628': '\u064a\u0627 \u0634\u0628\u0627\u0628\u060c \u0627\u0644\u062c\u064a\u0644 \u0627\u0644\u0642\u0627\u062f\u0645 \u0647\u0648 \u0627\u0644\u0644\u064a \u0647\u064a\u062f\u0641\u0639 \u062a\u0645\u0646 \u0627\u0644\u0647\u062f\u0631 \u0627\u0644\u0644\u064a \u0628\u0646\u0639\u0645\u0644\u0647 \u0627\u0644\u0646\u0647\u0627\u0631\u062f\u0647.',
    '\u0623\u0635\u062d\u0627\u0628 \u0627\u0644\u0645\u062d\u0644\u0627\u062a \u0648\u0627\u0644\u0645\u0634\u0627\u0631\u064a\u0639 \u0627\u0644\u0635\u063a\u064a\u0631\u0629': '\u064a\u0627 \u0635\u0627\u062d\u0628 \u0627\u0644\u0645\u0634\u0631\u0648\u0639\u060c \u062a\u0648\u0641\u064a\u0631 \u0627\u0644\u0645\u064a\u0627\u0647 = \u062a\u0648\u0641\u064a\u0631 \u0641\u064a \u0627\u0644\u0641\u0627\u062a\u0648\u0631\u0629 = \u0631\u0628\u062d \u0623\u0643\u062a\u0631.',
    '\u0633\u0643\u0627\u0646 \u0627\u0644\u0639\u0645\u0627\u0631\u0627\u062a \u0648\u0627\u0644\u0645\u062c\u0645\u0639\u0627\u062a \u0627\u0644\u0633\u0643\u0646\u064a\u0629': '\u0644\u0648 \u0643\u0644 \u0634\u0642\u0629 \u0641\u064a \u0627\u0644\u0639\u0645\u0627\u0631\u0629 \u0648\u0641\u0651\u0631\u062a 20 \u0644\u062a\u0631 \u0641\u064a \u0627\u0644\u064a\u0648\u0645\u060c \u0647\u062a\u0648\u0641\u0651\u0631\u0648\u0627 \u0622\u0644\u0627\u0641 \u0627\u0644\u0644\u062a\u0631\u0627\u062a \u0634\u0647\u0631\u064a\u0627\u064b!',
    '\u0627\u0644\u0623\u0633\u0631 \u0627\u0644\u0643\u0628\u064a\u0631\u0629': '\u0627\u0644\u0639\u064a\u0644\u0629 \u0627\u0644\u0643\u0628\u064a\u0631\u0629 = \u0641\u0631\u0635\u0629 \u0643\u0628\u064a\u0631\u0629 \u0644\u0644\u062a\u0648\u0641\u064a\u0631. \u0643\u0644 \u0641\u0631\u062f \u064a\u0648\u0641\u0651\u0631 \u0634\u0648\u064a\u0629 = \u0641\u0627\u062a\u0648\u0631\u0629 \u0623\u0635\u063a\u0631 \u0628\u0643\u062a\u064a\u0631.',
    '\u0627\u0644\u0645\u0632\u0627\u0631\u0639\u064a\u0646': '\u0627\u0644\u0645\u0627\u0621 \u0647\u0648 \u0631\u0648\u062d \u0627\u0644\u0623\u0631\u0636 \u2014 \u0627\u0644\u0631\u064a \u0627\u0644\u0630\u0643\u064a \u0628\u064a\u0648\u0641\u0651\u0631 \u0639\u0644\u064a\u0643 \u0648\u0628\u064a\u0632\u0648\u0651\u062f \u0627\u0644\u0625\u0646\u062a\u0627\u062c.'
  };
  var hook = audHook[audience] || '\u0627\u062d\u0646\u0627 \u0643\u0644\u0646\u0627 \u0645\u0633\u0624\u0648\u0644\u064a\u0646 \u0639\u0646 \u0627\u0644\u062d\u0641\u0627\u0638 \u0639\u0644\u0649 \u0627\u0644\u0645\u064a\u0627\u0647.';
  var platNote = {
    '\u0641\u064a\u0633\u0628\u0648\u0643': '(\u0645\u0646\u0627\u0633\u0628 \u0644\u0641\u064a\u0633\u0628\u0648\u0643)',
    '\u0648\u0627\u062a\u0633\u0627\u0628': '(\u0645\u0646\u0627\u0633\u0628 \u0644\u0648\u0627\u062a\u0633\u0627\u0628)',
    '\u062a\u064a\u0643 \u062a\u0648\u0643': '(\u0642\u0635\u064a\u0631 \u0648\u062c\u0630\u0627\u0628 \u0644\u062a\u064a\u0643 \u062a\u0648\u0643)',
    '\u0625\u0646\u0633\u062a\u062c\u0631\u0627\u0645': '(\u062c\u0627\u0647\u0632 \u0644\u0625\u0646\u0633\u062a\u062c\u0631\u0627\u0645)',
    '\u0644\u0627\u0641\u062a\u0629 \u0625\u0639\u0644\u0627\u0646\u064a\u0629': '(\u0645\u0646\u0627\u0633\u0628 \u0644\u0644\u0637\u0628\u0627\u0639\u0629)'
  };
  var title = t.open + message.substring(0, 40) + (message.length > 40 ? '...' : '');
  var body = hook + '\n\n' + t.emo + '\n' + message + '\n\n' + t.close;
  var cta = '\u062d\u0645\u0651\u0644 \u0648\u0641\u0631\u0647\u0627 \u0627\u0644\u0622\u0646 \u0648\u0627\u0628\u062f\u0623 \u062a\u0631\u0634\u064a\u062f \u0627\u0633\u062a\u0647\u0644\u0627\u0643\u0643! \ud83d\udca7 ' + (platNote[platform] || '');
  var tags = '#\u062a\u0631\u0634\u064a\u062f_\u0627\u0644\u0645\u064a\u0627\u0647 #\u0648\u0641\u0631\u0647\u0627 #\u0645\u0635\u0631 #\u062a\u0648\u0641\u064a\u0631_\u0627\u0644\u0645\u064a\u0627\u0647';
  var plain = '\ud83c\udfaf \u0627\u0644\u0639\u0646\u0648\u0627\u0646:\n' + title + '\n\n\ud83d\udcdd \u0646\u0635 \u0627\u0644\u0625\u0639\u0644\u0627\u0646:\n' + body + '\n\n\ud83d\udca1 \u0646\u062f\u0627\u0621 \u0644\u0644\u062a\u0635\u0631\u0641:\n' + cta + '\n\n' + tags;
  return { title: title, body: body.replace(/\n/g, '<br>'), cta: cta, tags: tags, plain: plain };
}

function copyAd() {
  if (!lastAdText) return;
  navigator.clipboard.writeText(lastAdText).then(function() {
    var btn = document.getElementById('copyAdBtn');
    btn.textContent = '✅ تم النسخ!';
    setTimeout(function(){ btn.innerHTML = '📋 نسخ الإعلان'; }, 2000);
  });
}
