var adCurrent = 0;
var adTimer = null;

function initAdBoard() {
  var track = document.getElementById('adTrack');
  var dotsC = document.getElementById('adDots');
  if (!track || !dotsC) return;

  track.innerHTML = '';
  dotsC.innerHTML = '';

  adSlides.forEach(function(s, i) {
    var slide = document.createElement('div');
    slide.className = 'ad-slide theme-' + s.theme;
    slide.innerHTML =
      '<div class="ad-slide-icon">' + s.icon + '</div>' +
      '<div class="ad-slide-body">' +
        '<div class="ad-slide-tag">' + s.tag + '</div>' +
        '<div class="ad-slide-title">' + s.title + '</div>' +
        '<div class="ad-slide-desc">' + s.desc + '</div>' +
        '<button class="ad-slide-cta" onclick="adCtaClick(' + i + ')">' + s.cta + '</button>' +
      '</div>';
    track.appendChild(slide);

    var dot = document.createElement('button');
    dot.className = 'ad-dot' + (i === 0 ? ' active' : '');
    dot.onclick = function() { goToAd(i); };
    dotsC.appendChild(dot);
  });

  adTimer = setInterval(function() {
    goToAd((adCurrent + 1) % adSlides.length);
  }, 5000);
}

function goToAd(idx) {
  adCurrent = idx;
  var track = document.getElementById('adTrack');
  if (track) track.style.transform = 'translateX(' + (idx * -100) + '%)';
  document.querySelectorAll('.ad-dot').forEach(function(d, i) {
    d.classList.toggle('active', i === idx);
  });
}

function adCtaClick(idx) {
  if (idx === 0) switchTab('dashboard');
  else if (idx === 1) switchTab('calculator');
  else if (idx === 2) switchTab('dashboard');
}

// init when tips tab is opened
var origSwitchTab = switchTab;
switchTab = function(id) {
  origSwitchTab(id);
  if (id === 'tips') {
    setTimeout(function() {
      initAdBoard();
      initTipsCenter();
    }, 50);
  }
};
