function handleBillUpload(input) {
  var file = input.files[0];
  if (!file) return;
  document.getElementById('scanReadyState').style.display = 'none';
  document.getElementById('scanLoadingState').style.display = 'block';
  setTimeout(function() {
    document.getElementById('scanReadyState').style.display = 'block';
    document.getElementById('scanLoadingState').style.display = 'none';
    var val = Math.floor(Math.random()*120)+90;
    billFiles.push({ id:'b'+Date.now(), name: file.name, usage: val });
    userState.usage = val;
    saveDayUsage(todayIdx, val);
    refreshAll(); renderBills();
    input.value = '';
  }, 1800);
}

// ===== WEEK BARS & STATS =====
var DAY_NAMES = ['أحد','إثنين','ثلاثاء','أربعاء','خميس','جمعة','سبت']; // 0=Sun..6=Sat

// Get week key like "2026-W24" so data resets each new week
function getWeekKey() {
  var now = new Date();
  var jan1 = new Date(now.getFullYear(), 0, 1);
  var week = Math.ceil(((now - jan1) / 86400000 + jan1.getDay() + 1) / 7);
  return now.getFullYear() + '-W' + week;
}

// Load this week's data from localStorage
function loadWeekData() {
  var key = 'waferha_week_' + getWeekKey();
  try {
    var raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : {};
  } catch(e) { return {}; }
}

// Save a single day's value
function saveDayUsage(dayIdx, val) {
  var key = 'waferha_week_' + getWeekKey();
  var data = loadWeekData();
  data[dayIdx] = val;
  localStorage.setItem(key, JSON.stringify(data));
}

var todayIdx = new Date().getDay(); // 0=Sun

function renderWeekBars() {
  var c = document.getElementById('weekBarsContainer');
  if (!c) return;

  var weekData = loadWeekData();
  // Always reflect current userState in today's slot visually (but don't save yet)
  if (userState.usage > 0) weekData[todayIdx] = userState.usage;

  var limit = userState.alertLimit;
  var vals = Object.values(weekData).filter(function(v){ return v > 0; });
  var max = vals.length ? Math.max.apply(null, vals) : limit;
  if (max < limit) max = limit;

  c.innerHTML = '';
  for (var i = 0; i < 7; i++) {
    var val = weekData[i] || 0;
    var pct = val === 0 ? 4 : Math.round((val / max) * 100);
    var cls = val === 0 ? 'ok' : val > limit ? 'over' : val > limit * 0.85 ? 'warn' : 'ok';
    var isToday = (i === todayIdx);
    if (isToday) cls += ' today';
    var col = document.createElement('div');
    col.className = 'day-bar-col';
    col.title = val > 0 ? DAY_NAMES[i] + ': ' + val + ' لتر' : DAY_NAMES[i];
    col.innerHTML =
      '<div class="day-bar ' + cls + '" style="height:' + pct + '%;opacity:' + (val === 0 ? '.2' : '1') + ';"></div>' +
      '<div class="day-lbl" style="' + (isToday ? 'color:#1E3A8A;font-weight:900;' : '') + '">' + DAY_NAMES[i] + '</div>';
    c.appendChild(col);
  }
}

function updateStatCards() {
  var usage = userState.usage;
  var limit = userState.alertLimit;
  var saved = usage > 0 ? Math.max(0, (limit - usage)) * 30 : 0;
  var cost = usage > 0 ? ((usage * 30) / 1000 * 1.5).toFixed(1) : '0.0';
  var trendToday = usage === 0 ? '<span class="stat-trend good">— أضف بياناتك</span>' :
    usage < limit * 0.75 ? '<span class="stat-trend good">↓ ممتاز! أقل من الهدف</span>' :
    usage < limit ? '<span class="stat-trend warn">⚠ قريب من الحد</span>' :
    '<span class="stat-trend warn">↑ تجاوزت الحد!</span>';
  var statToday = document.getElementById('stat-today');
  var statSaved = document.getElementById('stat-saved');
  var statCost  = document.getElementById('stat-cost');
  if (statToday) statToday.innerHTML = (usage === 0 ? '—' : usage) + ' <span style="font-size:12px;font-weight:700;color:#64748B;">لتر</span><br>' + trendToday;
  if (statSaved) statSaved.innerHTML = (usage === 0 ? '—' : saved.toLocaleString()) + ' <span style="font-size:12px;font-weight:700;color:#64748B;">لتر</span>';
  if (statCost)  statCost.innerHTML  = cost + ' <span style="font-size:12px;font-weight:700;color:#64748B;">وحدة</span>';
}

setTimeout(function() { renderWeekBars(); updateStatCards(); updateSavingHint(); }, 600);
