function renderBills() {
  var c = document.getElementById('scannedBillsContainer');
  document.getElementById('billsCountBadge').textContent = billFiles.length + ' فواتير';
  if (!billFiles.length) { c.innerHTML = '<div class="bills-list-empty">لا توجد مستندات حالياً</div>'; return; }
  c.innerHTML = '';
  billFiles.forEach(function(b) {
    var d = document.createElement('div');
    d.className = 'bill-item';
    d.innerHTML = '<div class="bill-item-info"><svg viewBox="0 0 24 24" style="width:14px;height:14px;stroke:#3B82F6;fill:none;stroke-width:2;flex-shrink:0;"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14,2 14,8 20,8"/></svg><div><div class="bill-name">'+b.name+'</div><div class="bill-usage">'+b.usage+' لتر</div></div></div><button class="btn-del" onclick="deleteBill(\''+b.id+'\')"><svg viewBox="0 0 24 24"><polyline points="3,6 5,6 21,6"/><path d="M19,6l-1,14a2,2,0,0,1-2,2H8a2,2,0,0,1-2-2L5,6"/><path d="M10,11v6M14,11v6"/><path d="M9,6V4a1,1,0,0,1,1-1h4a1,1,0,0,1,1,1V6"/></svg></button>';
    c.appendChild(d);
  });
}

function deleteBill(id) {
  billFiles = billFiles.filter(function(b){ return b.id !== id; });
  renderBills();
}

function calculateSavings() {
  var fam = parseInt(document.getElementById('input-familyNum').value);
  var daily = parseInt(document.getElementById('input-personUsage').value);
  var shower = parseInt(document.getElementById('input-showerTime').value);
  var tariff = parseFloat(document.getElementById('input-tariffRate').value);
  document.getElementById('val-familyNum').textContent = fam + ' أفراد';
  document.getElementById('val-personUsage').textContent = daily + ' لتر';
  document.getElementById('val-showerTime').textContent = shower + ' دقائق';
  document.getElementById('val-tariffRate').textContent = tariff + ' وحدة';
  var monthly = fam * daily * 30;
  var cost = (monthly/1000)*tariff;
  var saved = Math.max(0,(daily-85)*fam*30);
  var savedMoney = (saved/1000)*tariff;
  document.getElementById('res-monthlyLiters').textContent = monthly.toLocaleString();
  document.getElementById('res-monthlyCost').textContent = cost.toFixed(1);
  document.getElementById('res-savedWater').textContent = saved.toLocaleString();
  document.getElementById('res-savedMoney').textContent = savedMoney.toFixed(1);
}

function renderFeedbacks() {
  var c = document.getElementById('feedbackList');
  document.getElementById('feedbackCountBadge').textContent = feedbacks.length + ' سجلات';
  if (!feedbacks.length) { c.innerHTML = '<div style="text-align:center;padding:32px;font-size:12px;color:#94A3B8;">لا توجد سجلات حالية.</div>'; return; }
  c.innerHTML = '';
  feedbacks.forEach(function(f) {
    var bc = f.type==='bug'?'badge-bug':f.type==='suggestion'?'badge-suggestion':'badge-other';
    var bt = f.type==='bug'?'مشكلة':f.type==='suggestion'?'اقتراح':'أخرى';
    var d = document.createElement('div');
    d.className = 'feedback-item';
    d.innerHTML = '<div class="feedback-meta"><span class="feedback-name">'+f.senderName+'</span><span class="feedback-email">('+f.email+')</span><span class="badge '+bc+'">'+bt+'</span></div><div class="feedback-msg">'+f.message+'</div><div class="feedback-date">'+f.date+'</div>';
    c.appendChild(d);
  });
}

