function goToDashboard() {
  var ov = document.getElementById('_vidOverlay');
  if (ov) { var v = ov.querySelector('video'); if(v){v.pause();v.src='';} ov.parentNode.removeChild(ov); }
  userState.name = 'المستخدم التجريبي';
  userState.email = 'demo@waferha.sa';
  if (typeof saveSession === 'function') saveSession();
  if (typeof showDashboard === 'function') showDashboard();
}

function openVideo() {
  var ex = document.getElementById('_vidOverlay');
  if (ex) ex.parentNode.removeChild(ex);
  var ov = document.createElement('div');
  ov.id = '_vidOverlay';
  var btn = document.createElement('button');
  btn.id = '_vidCloseBtn';
  btn.textContent = '✕ دخول للتطبيق';
  btn.setAttribute('onclick', 'goToDashboard()');
  var vid = document.createElement('video');
  vid.setAttribute('controls', '');
  vid.setAttribute('playsinline', '');
  vid.setAttribute('webkit-playsinline', '');
  vid.src = _videoB64;
  vid.addEventListener('ended', function() { goToDashboard(); });
  ov.appendChild(btn);
  ov.appendChild(vid);
  document.body.appendChild(ov);
  setTimeout(function(){ vid.play(); }, 100);
}

// ============ CAMERA FLOW DETECTION ============
var camStream = null;
var camAnalysisInterval = null;
var camShowerSeconds = 0;
var camShowerTimer = null;
var camOpen = false;

function openCamera() {
  // Trigger file input - works from any context including content://
  document.getElementById('camFileInput').click();
}

var camDetectedFlow = null;
var camDuration = 5;

function closeCamera() {
  camOpen = false;
  camDetectedFlow = null;
  document.getElementById('cameraModal').classList.remove('open');
}

function changeDuration(delta) {
  camDuration = Math.max(1, Math.min(60, camDuration + delta));
  document.getElementById('camDurationVal').textContent = camDuration;
}

function handleCamFile(input) {
  if (!input.files || !input.files[0]) return;
  var file = input.files[0];
  var url = URL.createObjectURL(file);

  document.getElementById('cameraModal').classList.add('open');
  camOpen = true;

  // Show preview
  var wrap = document.getElementById('camPreviewWrap');
  wrap.innerHTML = '<img src="' + url + '" style="width:100%;max-height:260px;object-fit:cover;display:block;">';

  // Show analyzing state
  var resEl = document.getElementById('camResult');
  resEl.style.background = 'rgba(59,130,246,.2)';
  resEl.style.borderColor = 'rgba(59,130,246,.5)';
  resEl.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;gap:8px;"><div style="width:16px;height:16px;border:2px solid #60a5fa;border-top-color:transparent;border-radius:50%;animation:spin .8s linear infinite;"></div> \u062c\u0627\u0631\u064a \u062a\u062d\u0644\u064a\u0644 \u0627\u0644\u0635\u0648\u0631\u0629...</div>';
  document.getElementById('camAddBtn').style.display = 'none';
  document.getElementById('camDurationWrap').style.display = 'none';

  // Read image and analyze
  var reader = new FileReader();
  reader.onload = function(e) {
    var b64 = e.target.result.split(',')[1];
    detectWaterFlowAI(b64).then(function(result) {
      camDetectedFlow = result;
      // Show smart questionnaire instead of raw result
      showCamQuestionnaire(resEl, result);
    });
  };
  reader.readAsDataURL(file);
}

// Smart questionnaire after image analysis
var camAnswers = { type: null, duration: 5, people: 1 };

function showCamQuestionnaire(resEl, analysisResult) {
  // Step 1: show detected type + ask device type
  var detected = analysisResult.isFlowing ? '\u2705 \u062a\u0645 \u0627\u0643\u062a\u0634\u0627\u0641 \u0645\u064a\u0627\u0647' : '\u26a0\ufe0f \u0644\u0645 \u064a\u062a\u0636\u062d \u0648\u062c\u0648\u062f \u0645\u064a\u0627\u0647 \u0648\u0627\u0636\u062d';
  resEl.style.background = analysisResult.isFlowing ? 'rgba(16,185,129,.15)' : 'rgba(245,158,11,.15)';
  resEl.style.borderColor = analysisResult.isFlowing ? 'rgba(16,185,129,.5)' : 'rgba(245,158,11,.5)';

  resEl.innerHTML =
    '<div style="font-size:13px;font-weight:800;color:#fff;margin-bottom:12px;">' + detected + '</div>' +
    '<div style="font-size:12px;color:rgba(255,255,255,.85);margin-bottom:10px;">\u0633\u0624\u0627\u0644 1/3: \u0646\u0648\u0639 \u0627\u0644\u062c\u0647\u0627\u0632</div>' +
    '<div style="display:flex;gap:8px;justify-content:center;flex-wrap:wrap;">' +
      '<button onclick="camChooseType(\'shower\',this)" style="background:rgba(59,130,246,.3);border:1px solid rgba(59,130,246,.6);color:#fff;padding:8px 14px;border-radius:12px;font-size:12px;font-weight:700;cursor:pointer;font-family:Almarai,sans-serif;">\ud83d\udebf \u062f\u0634</button>' +
      '<button onclick="camChooseType(\'sink\',this)" style="background:rgba(59,130,246,.3);border:1px solid rgba(59,130,246,.6);color:#fff;padding:8px 14px;border-radius:12px;font-size:12px;font-weight:700;cursor:pointer;font-family:Almarai,sans-serif;">\ud83d\udea7 \u062d\u0646\u0641\u064a\u0629</button>' +
      '<button onclick="camChooseType(\'washing\',this)" style="background:rgba(59,130,246,.3);border:1px solid rgba(59,130,246,.6);color:#fff;padding:8px 14px;border-radius:12px;font-size:12px;font-weight:700;cursor:pointer;font-family:Almarai,sans-serif;">\ud83e\uddf7 \u063a\u0633\u0627\u0644\u0629</button>' +
      '<button onclick="camChooseType(\'garden\',this)" style="background:rgba(59,130,246,.3);border:1px solid rgba(59,130,246,.6);color:#fff;padding:8px 14px;border-radius:12px;font-size:12px;font-weight:700;cursor:pointer;font-family:Almarai,sans-serif;">\ud83c\udf31 \u062d\u062f\u064a\u0642\u0629</button>' +
    '</div>';
}

function camChooseType(type, btn) {
  camAnswers.type = type;
  // Highlight selected
  btn.parentNode.querySelectorAll('button').forEach(function(b){ b.style.background='rgba(59,130,246,.3)'; });
  btn.style.background = 'rgba(16,185,129,.5)';

  // Step 2: ask duration after short delay
  setTimeout(function() {
    var resEl = document.getElementById('camResult');
    var typeNames = { shower:'\u0627\u0644\u062f\u0634', sink:'\u0627\u0644\u062d\u0646\u0641\u064a\u0629', washing:'\u0627\u0644\u063a\u0633\u0627\u0644\u0629', garden:'\u0631\u064a \u0627\u0644\u062d\u062f\u064a\u0642\u0629' };
    resEl.innerHTML =
      '<div style="font-size:12px;color:rgba(255,255,255,.85);margin-bottom:10px;">\u0633\u0624\u0627\u0644 2/3: \u0643\u0645 \u062f\u0642\u064a\u0642\u0629 \u0643\u0627\u0646' + (typeNames[type]||'') + '\u0634\u063a\u0627\u0644?</div>' +
      '<div style="display:flex;align-items:center;justify-content:center;gap:12px;margin-bottom:10px;">' +
        '<button onclick="camChangeDur(-1)" style="background:rgba(255,255,255,.2);border:none;color:#fff;width:36px;height:36px;border-radius:50%;font-size:20px;cursor:pointer;">-</button>' +
        '<span id="camDurDisplay" style="color:#fff;font-size:28px;font-weight:900;min-width:60px;text-align:center;">5</span>' +
        '<span style="color:rgba(255,255,255,.7);font-size:13px;">\u062f\u0642\u064a\u0642\u0629</span>' +
        '<button onclick="camChangeDur(1)" style="background:rgba(255,255,255,.2);border:none;color:#fff;width:36px;height:36px;border-radius:50%;font-size:20px;cursor:pointer;">+</button>' +
      '</div>' +
      '<button onclick="camAskPeople()" style="background:rgba(59,130,246,.6);border:none;color:#fff;padding:9px 24px;border-radius:12px;font-size:12px;font-weight:800;cursor:pointer;font-family:Almarai,sans-serif;">\u0627\u0644\u062a\u0627\u0644\u064a \u2192</button>';
    camAnswers.duration = 5;
  }, 400);
}

function camChangeDur(delta) {
  camAnswers.duration = Math.max(1, Math.min(120, (camAnswers.duration||5) + delta));
  var el = document.getElementById('camDurDisplay');
  if (el) el.textContent = camAnswers.duration;
}

function camAskPeople() {
  var resEl = document.getElementById('camResult');
  resEl.innerHTML =
    '<div style="font-size:12px;color:rgba(255,255,255,.85);margin-bottom:10px;">\u0633\u0624\u0627\u0644 3/3: \u0643\u0645 \u0634\u062e\u0635 \u0627\u0633\u062a\u062e\u062f\u0645 \u0647\u0630\u0627 \u0627\u0644\u062c\u0647\u0627\u0632 \u0627\u0644\u0646\u0647\u0627\u0631\u062f\u0647?</div>' +
    '<div style="display:flex;gap:8px;justify-content:center;flex-wrap:wrap;">' +
      '<button onclick="camFinalize(1)" style="background:rgba(59,130,246,.3);border:1px solid rgba(59,130,246,.6);color:#fff;padding:8px 16px;border-radius:12px;font-size:13px;font-weight:700;cursor:pointer;font-family:Almarai,sans-serif;">1</button>' +
      '<button onclick="camFinalize(2)" style="background:rgba(59,130,246,.3);border:1px solid rgba(59,130,246,.6);color:#fff;padding:8px 16px;border-radius:12px;font-size:13px;font-weight:700;cursor:pointer;font-family:Almarai,sans-serif;">2</button>' +
      '<button onclick="camFinalize(3)" style="background:rgba(59,130,246,.3);border:1px solid rgba(59,130,246,.6);color:#fff;padding:8px 16px;border-radius:12px;font-size:13px;font-weight:700;cursor:pointer;font-family:Almarai,sans-serif;">3</button>' +
      '<button onclick="camFinalize(4)" style="background:rgba(59,130,246,.3);border:1px solid rgba(59,130,246,.6);color:#fff;padding:8px 16px;border-radius:12px;font-size:13px;font-weight:700;cursor:pointer;font-family:Almarai,sans-serif;">4+</button>' +
    '</div>';
}

function camFinalize(people) {
  camAnswers.people = people;

  // Flow rates per device type (liters/minute)
  var flowRates = { shower: 9, sink: 6, washing: 12, garden: 15 };
  var flowRate = (camDetectedFlow && camDetectedFlow.flowRate) || flowRates[camAnswers.type] || 8;
  // Use device-specific rate if AI wasn't conclusive
  if (!camDetectedFlow || !camDetectedFlow.isFlowing) {
    flowRate = flowRates[camAnswers.type] || 8;
  }

  var totalLiters = Math.round(flowRate * camAnswers.duration * camAnswers.people * 10) / 10;
  var typeNames = { shower:'\u062f\u0634', sink:'\u062d\u0646\u0641\u064a\u0629', washing:'\u063a\u0633\u0627\u0644\u0629', garden:'\u0631\u064a \u062d\u062f\u064a\u0642\u0629' };

  var resEl = document.getElementById('camResult');
  resEl.style.background = 'rgba(16,185,129,.2)';
  resEl.style.borderColor = 'rgba(16,185,129,.6)';
  resEl.innerHTML =
    '<div style="font-size:14px;font-weight:900;color:#fff;margin-bottom:8px;">\ud83d\udca7 \u0646\u062a\u064a\u062c\u0629 \u0627\u0644\u062a\u062d\u0644\u064a\u0644</div>' +
    '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;text-align:center;">' +
      '<div style="background:rgba(255,255,255,.1);border-radius:10px;padding:8px;">' +
        '<div style="font-size:10px;color:rgba(255,255,255,.6);">\u0646\u0648\u0639 \u0627\u0644\u062c\u0647\u0627\u0632</div>' +
        '<div style="font-size:16px;font-weight:900;color:#fff;">' + (typeNames[camAnswers.type]||'-') + '</div>' +
      '</div>' +
      '<div style="background:rgba(255,255,255,.1);border-radius:10px;padding:8px;">' +
        '<div style="font-size:10px;color:rgba(255,255,255,.6);">\u0627\u0644\u0645\u062f\u0629</div>' +
        '<div style="font-size:16px;font-weight:900;color:#fff;">' + camAnswers.duration + ' \u062f\u0642\u064a\u0642\u0629</div>' +
      '</div>' +
      '<div style="background:rgba(255,255,255,.1);border-radius:10px;padding:8px;">' +
        '<div style="font-size:10px;color:rgba(255,255,255,.6);">\u0645\u0639\u062f\u0644 \u0627\u0644\u062a\u062f\u0641\u0642</div>' +
        '<div style="font-size:16px;font-weight:900;color:#fff;">' + flowRate + ' \u0644/\u062f</div>' +
      '</div>' +
      '<div style="background:rgba(16,185,129,.3);border-radius:10px;padding:8px;">' +
        '<div style="font-size:10px;color:rgba(255,255,255,.6);">\u0625\u062c\u0645\u0627\u0644\u064a \u0627\u0644\u0627\u0633\u062a\u0647\u0644\u0627\u0643</div>' +
        '<div style="font-size:20px;font-weight:900;color:#4ade80;">' + totalLiters + ' \u0644\u062a\u0631</div>' +
      '</div>' +
    '</div>';

  // Store result and show add button
  camDetectedFlow = { isFlowing: true, flowRate: flowRate, totalLiters: totalLiters };
  document.getElementById('camAddBtn').style.display = 'inline-block';
}

function confirmCamUsage() {
  var totalLiters = camDetectedFlow && camDetectedFlow.totalLiters
    ? camDetectedFlow.totalLiters
    : Math.round((camDetectedFlow ? camDetectedFlow.flowRate : 8) * camAnswers.duration * 10) / 10;
  var cur = userState.usage || 0;
  userState.usage = Math.round((cur + totalLiters) * 10) / 10;
  if (typeof saveDayUsage === 'function') saveDayUsage(todayIdx, userState.usage);
  if (typeof refreshAll === 'function') refreshAll();
  closeCamera();
  showCamToast('\ud83d\udca7 \u062a\u0645 \u0625\u0636\u0627\u0641\u0629 ' + totalLiters + ' \u0644\u062a\u0631 \u0644\u0627\u0633\u062a\u0647\u0644\u0627\u0643 \u0627\u0644\u064a\u0648\u0645');
  // Reset
  camAnswers = { type: null, duration: 5, people: 1 };
}


function showCamToast(msg) {
  var t = document.createElement('div');
  t.textContent = msg;
  t.style.cssText = 'position:fixed;bottom:100px;left:50%;transform:translateX(-50%);background:#1E3A8A;color:#fff;padding:12px 20px;border-radius:99px;font-size:13px;font-weight:700;z-index:99999;white-space:nowrap;box-shadow:0 4px 20px rgba(0,0,0,.3);font-family:Almarai,sans-serif;';
  document.body.appendChild(t);
  setTimeout(function() { t.style.opacity='0'; t.style.transition='.4s'; setTimeout(function(){t.remove();},400); }, 3000);
}
