    ctx.translate(x, y);
    ctx.fillStyle = '#1E3A8A';
    ctx.strokeStyle = '#60A5FA';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.roundRect(-size / 2, -size / 2, size, size, r);
