    var now = startOfDay(new Date());
    var currentRange = getAnalyticsRange(analyticsState.period, now, store);
    var compareRange = resolveCompareRange(currentRange);

    if (analyticsState.compareMode === 'custom' && (!analyticsState.compareStart || !analyticsState.compareEnd)) {
      analyticsState.compareStart = formatDateInputValue(compareRange.start);
      analyticsState.compareEnd = formatDateInputValue(compareRange.end);
      saveAnalyticsViewState();
      compareRange = resolveCompareRange(currentRange);
    }

    var current = buildAnalyticsSeries(currentRange, store);
    var previous = buildAnalyticsSeries(compareRange, store);
    var comparison = compareSeries(current, previous);
    var hasData = Object.keys(store || {}).some(function(key) { return Number(store[key]) > 0; });
    var todayValue = Number(store[dateKey(now)] || 0);
    var topPoint = current.maxPoint && Number(current.maxPoint.value) > 0 ? current.maxPoint : null;
